What does the following program print?

```cpp
#include <iostream>

class Box {
private:
    int m_side;
public:
    Box(int side) { m_side = side; }
    int getSide() const { return m_side; }
};

int main() {
    Box b{ 7 };
    std::cout << b.getSide() << '\n';
    return 0;
}
```

What does the following program print?

```cpp
#include <iostream>
#include <string>

class Label {
private:
    std::string m_text;
public:
    Label() { m_text = "default"; }
    Label(const std::string& t) { m_text = t; }
    const std::string& getText() const { return m_text; }
};

int main() {
    Label a;
    Label b{ "hello" };
    std::cout << a.getText() << '\n';
    std::cout << b.getText() << '\n';
    return 0;
}
```

